## Common Patterns

### App Router Structure
```
app/
├── page.tsx           # Route page (Server Component)
├── layout.tsx         # Root layout
├── loading.tsx        # Loading UI
├── error.tsx          # Error boundary
├── not-found.tsx      # 404 page
├── globals.css        # Global styles
├── proxy.ts           # Request routing (replaces middleware.ts in Next.js 16+)
└── (group)/
    └── page.tsx       # Route group
```

### Server Component with Data
```tsx
// app/page.tsx
import { db } from '@/lib/db';
import { UserList } from '@/components/UserList';

export default async function Page() {
  const users = await db.user.findMany({
    where: { active: true },
    orderBy: { createdAt: 'desc' }
  });

  return (
    <main>
      <h1>Users</h1>
      <UserList users={users} />
    </main>
  );
}
```

### Server Action
```tsx
// app/actions.ts
'use server';

import { db } from '@/lib/db';
import { revalidatePath } from 'next/cache';

export async function createUser(formData: FormData) {
  const name = formData.get('name') as string;

  await db.user.create({
    data: { name }
  });

  revalidatePath('/');
  return { success: true };
}
```

> **Best practice**: Use file-level `'use server'` in `app/actions.ts` and omit it from individual exported functions to avoid "stream already consumed" runtime errors.

### API Route Handler
```tsx
// app/api/users/route.ts
import { NextResponse } from 'next/server';
import { db } from '@/lib/db';

export async function GET(request: Request) {
  const users = await db.user.findMany();
  return NextResponse.json(users);
}

export async function POST(request: Request) {
  const data = await request.json();
  const user = await db.user.create({ data });
  return NextResponse.json(user, { status: 201 });
}
```

### Proxy (Request Routing) — replaces middleware.ts in Next.js 16+

**`middleware.ts` is deprecated in Next.js 16. Use `proxy.ts` instead.** Proxy runs on Node.js runtime by default. The `runtime = 'edge'` export is not available in `proxy.ts`.

```tsx
// proxy.ts (root of project, same level as app/)
import { NextResponse } from 'next/server';
import type { NextRequest } from 'next/server';

export function proxy(request: NextRequest) {
  // Auth check example
  const token = request.cookies.get('session');
  if (!token && request.nextUrl.pathname.startsWith('/dashboard')) {
    return NextResponse.redirect(new URL('/login', request.url));
  }

  // Rewrite example
  if (request.nextUrl.pathname.startsWith('/legacy')) {
    return NextResponse.rewrite(new URL('/new-route', request.url));
  }

  return NextResponse.next();
}

export const config = {
  matcher: [
    // Match all paths except static assets
    '/((?!_next/static|_next/image|favicon.ico).*)',
  ],
};
```

> **Migration**: ⚠ Verify the codemod exists before running: `npx @next/codemod@latest middleware-to-proxy .` (do NOT use `@canary` — canary builds are unstable). If the codemod is unavailable, manually rename `middleware.ts` → `proxy.ts` and the `middleware` export → `proxy`.

### ISR with Revalidation
```tsx
// app/page.tsx
export const revalidate = 60; // Revalidate every 60 seconds

export default async function Page() {
  const data = await fetch('https://api.example.com/data', {
    next: { revalidate: 60 }
  }).then(r => r.json());

  return <div>{data.content}</div>;
}

// Or on-demand via a route handler
export async function POST() {
  revalidatePath('/');
  return Response.json({ revalidated: true });
}
```

### `"use cache"` Directive (Next.js 16+)

The `"use cache"` directive caches the result of a function or component at the component level — stable in Next.js 16. Use it to replace the older experimental PPR pattern and for granular per-component caching.

```tsx
// Cache a component with time-based revalidation
'use cache';

export const revalidate = 300; // Revalidate every 5 minutes

export default async function CachedUserList() {
  const users = await db.user.findMany();
  return <ul>{users.map(u => <li key={u.id}>{u.name}</li>)}</ul>;
}

// Or with a tag for on-demand revalidation
'use cache';
export const tags = ['users'];

export default async function CachedUsers() { /* ... */ }
```

```tsx
// In a Server Action or Route Handler:
import { revalidateTag } from 'next/cache';
revalidateTag('users'); // Purge all cached components tagged 'users'
```

> **Important**: `"use cache"` and `'use server'` are mutually exclusive and cannot appear in the same file. Use `"use cache"` for cached data fetching; use `'use server'` (in a separate file like `app/actions.ts`) for mutations.

### React Compiler (v1.0 — ⚠ verify stable status before enabling)

⚠ **Verification required**: The stable status of React Compiler v1.0 should be verified via `npm info @babel/plugin-react-compiler` or the official React blog before enabling in production. If v1.0 stable is confirmed, enable in `next.config.ts`:

```ts
import type { NextConfig } from 'next';

const nextConfig: NextConfig = {
  // ⚠ If v1.0 stable: use 'compiler' key (not experimental)
  compiler: {
    reactCompiler: true,
  },
  // Fallback if still experimental in your installed version:
  // experimental: {
  //   reactCompiler: true,
  // },
};

export default nextConfig;
```

> When React Compiler is active, do not add manual `useMemo` or `useCallback` calls — the compiler handles this automatically and manual memoization can sometimes disable compiler optimizations on the same component.

