**Express 5.x (recommended):** Native async propagation — no wrapper needed.
```typescript
// Express 5: rejected promises are automatically forwarded to error handlers
app.get('/api/users/:id', async (req, res) => {
  const user = await prisma.user.findUnique({ where: { id: req.params.id } });
  if (!user) throw Object.assign(new Error('User not found'), { status: 404 });
  res.json(user);
});
