### View Transitions API (React 19 — Stable)
The View Transitions API is stable across all modern browsers (Chrome 111+, Safari 18.1, Firefox 121+). Wrap state changes in view transitions for smooth UI updates:
```tsx
// Wrap state changes in view transitions for smooth UI updates
'use client';

import { startTransition } from 'react';
import { useState } from 'react';

function ImageGallery({ images }) {
  const [selected, setSelected] = useState(images[0]);

  function handleSelect(img) {
    if (!document.startViewTransition) {
      setSelected(img);
      return;
    }
    document.startViewTransition(() => {
      startTransition(() => setSelected(img));
    });
  }

  return (
    <div>
      <img
        key={selected}
        src={selected}
        alt="selected"
        style={{ viewTransitionName: 'gallery-img' }}
      />
      <div>
        {images.map((img, i) => (
          <button key={i} onClick={() => handleSelect(img)}>
            <img src={img} alt="" />
          </button>
        ))}
      </div>
    </div>
  );
}
```

